export const downloadCt01Doc = rawData => {
  if (!rawData) {
    return;
  }

  const data = buildCt01PreviewData(rawData);
  const html = buildCt01DocumentHtml(data);
  const blob = new Blob(['\ufeff', html], { type: 'application/msword;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  const safeName = (data.hoTen || `phieu-${data.maPhieuTamTru || 'tam-tru'}`)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');

  link.href = url;
  link.download = `CT01-${safeName || 'findroommate'}.doc`;
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
  window.setTimeout(() => URL.revokeObjectURL(url), 1000);
};

